import { ChatOpenAI } from "@langchain/openai";
import { PromptTemplate } from "@langchain/core/prompts";
import { StructuredOutputParser } from "langchain/output";
import { z } from "zod";

const schema = z.object({
  invoiceNumber: z.string().describe("Unique invoice ID"),
  date: z.string().describe("Invoice date"),
  amount: z.number().describe("Total amount"),
  vendor: z.string().describe("Vendor name"),
});

const parser = StructuredOutputParser.fromZodSchema(schema);
const prompt = new PromptTemplate({
  template: "Extract invoice data: {format_instructions}\nDocument: {document}",
  inputVariables: ["document"],
  partialVariables: { format_instructions: parser.getFormatInstructions() },
});

const model = new ChatOpenAI({ model: "gpt-4o-mini", temperature: 0 });
const chain = prompt.pipe(model).pipe(parser);

const result = await chain.invoke({
  document: "Invoice #INV-1234 dated 2024-03-15 from Acme Corp: $2,500",
});
console.log(result);

