    try {
      const result = await chain.invoke({ document: doc.content });
      return { success: true, data: result, docId: doc.id };
    } catch (error) {
      return { success: false, error: error.message, docId: doc.id };
    }
  })
);
const validExtractions = batchResults.filter(r => r.success);

